#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005

int n, m;
int color[MAXN];
int edges[MAXN][2];

void dfs(int u, int c) {
    if (color[u] != c) return;
    color[u] = -c;
    for (int i = 0; i < n - 1; i++) {
        if (edges[i][0] == u) dfs(edges[i][1], c);
        if (edges[i][1] == u) dfs(edges[i][0], c);
    }
}

int main() {
    scanf("%d", &n);
    for (int i = 0; i < n - 1; i++) {
        scanf("%d %d", &edges[i][0], &edges[i][1]);
    }
    scanf("%d", &m);
    for (int i = 0; i < m; i++) {
        int t, u;
        scanf("%d %d", &t, &u);
        if (t == 0) {
            int count = 0;
            for (int j = 1; j <= n; j++) {
                if (color[j] == color[u]) count++;
            }
            printf("%d\n", count);
        } else {
            dfs(u, color[u]);
        }
    }
    return 0;
}

