import java.util.Scanner;
import java.util.ArrayList;
public class Main {
    static int n, m;
    static int[] color;
    static ArrayList<Integer>[] edges;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        n = sc.nextInt();
        color = new int[n + 1];
        edges = new ArrayList[n + 1];
        for (int i = 0; i <= n; i++) {
            edges[i] = new ArrayList<>();
        }
        for (int i = 0; i < n - 1; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            edges[u].add(v);
            edges[v].add(u);
        }
        m = sc.nextInt();
        for (int i = 0; i < m; i++) {
            int t = sc.nextInt();
            int u = sc.nextInt();
            if (t == 0) {
                int count = 0;
                for (int j = 1; j <= n; j++) {
                    if (color[j] == color[u]) count++;
                }
                System.out.println(count);
            } else {
                dfs(u, color[u]);
            }
        }
    }
    public static void dfs(int u, int c) {
        if (color[u] != c) return;
        color[u] = -c;
        for (int v : edges[u]) {
            dfs(v, c);
        }
    }
}

